// Load .env file if available (for Node.js environments)
if (typeof process !== 'undefined' && process.env) {
	import('dotenv').then(({ config: loadDotenv }) => loadDotenv()).catch(() => {});
}

// Global config object that can be set by the consuming application
let appConfig = null;

// Re-export wallet adapter functions
export { setWalletAdapter, getWalletAdapter, getAdapterProvider } from "../canton/walletAdapter.js";

/**
 * Initialize the library with a configuration object.
 * This should be called by the consuming application before using the library.
 * @param {Object} config - Configuration object with all required settings
 */
export function initializeConfig(config) {
	appConfig = config;
}

/**
 * Update the JWT token without re-initializing the full config.
 * Useful when refreshing tokens for custom validator connections.
 * @param {string} token - The new JWT token
 */
export function setJWTToken(token) {
	if (!appConfig) {
		appConfig = {};
	}
	appConfig.JWT_TOKEN = token;
}

/**
 * Get a configuration value from:
 * 1. App-provided config (if initializeConfig was called)
 * 2. Environment variables (process.env)
 */
export function getConfigValue(key) {
	// First check app-provided config
	if (appConfig && appConfig[key] !== undefined) {
		return appConfig[key];
	}

	// Then check environment variables
	if (typeof process !== 'undefined' && process.env && process.env[key]) {
		const value = process.env[key];
		if (value && value.trim().length > 0) {
			return value;
		}
	}

	return undefined;
}

